func (s *transactionServer) CreateTransaction(ctx context.Context, req *transaction.CreateTransactionRequest) (*transaction.CreateTransactionResponse, error) {
  // Simulate transaction processing
  if req.Amount <= 0 {
    return &transaction.CreateTransactionResponse{
      Success: false,
      Message: "Invalid amount",
    }, nil
  }
  
  // Check if from account has sufficient balance
  fromBalance, exists := s.balances[req.FromAccount]
  if !exists || fromBalance < req.Amount {
    return &transaction.CreateTransactionResponse{
      Success: false,
      Message: "Insufficient balance",
    }, nil
  }
  
  // Process transaction
  s.balances[req.FromAccount] -= req.Amount
  s.balances[req.ToAccount] += req.Amount
  
  return &transaction.CreateTransactionResponse{
    Success: true,
    Message: "Transaction completed successfully",
    TransactionId: req.TransactionId,
  }, nil
}

func (s *transactionServer) GetBalance(ctx context.Context, req *transaction.GetBalanceRequest) (*transaction.GetBalanceResponse, error) {
  balance, exists := s.balances[req.AccountId]
  if !exists {
    return &transaction.GetBalanceResponse{
      Balance: 0,
      Currency: "USD",
      AccountId: req.AccountId,
    }, nil
  }
  
  return &transaction.GetBalanceResponse{
    Balance: balance,
    Currency: "USD",
    AccountId: req.AccountId,
  }, nil
}

